63:- **QuickJS (recommended)** — a modern engine compliant with [ES2023](https://262.ecma-international.org/14.0/). Enable it with `js_engine qjs;`. Building from source requires the QuickJS library (see [Building from source](#building-from-source)). Read more: [QuickJS engine support for NJS](https://blog.nginx.org/blog/quickjs-engine-support-for-njs).
=== qjs class def ===
static JSClassDef qjs_fs_stats_class = {
    "Stats",
    .finalizer = qjs_fs_stats_finalizer,
    .exotic = & (JSClassExoticMethods) {
        .get_own_property = qjs_fs_stats_get_own_property,
        .get_own_property_names = qjs_fs_stats_get_own_property_names,
    },
};


static JSClassDef qjs_fs_filehandle_class = {
    "FileHandle",
    .finalizer = qjs_fs_filehandle_finalizer,
};

